const items=JSON.parse(dv.basket||"[]");
let dec=JSON.parse(dv.declined_deals||"[]");
const prev=dv.deal_match||"none";
if(prev!=="none"&&dec.indexOf(prev)===-1){
const hasCombo=items.some(it=>it.is_combo);
if(!hasCombo)dec.push(prev);
}
const PR=[723,724,725,726,710];
let pz=[],su=[],bw=0,ww=0,fr=0,cn=0,tl=0,bg=0,fi=0;
for(const it of items){
if(it.is_combo)continue;
const nm=(it.item_name||"").toLowerCase();
const id=parseInt(it.item_id)||0;
const ct=(it.category||"").toLowerCase();
if(ct==="pizzas"&&nm.includes("cheese pizza")){const m=nm.match(/(\d+)\s*inch/);pz.push(m?parseInt(m[1]):14);}
if(ct==="submarines")su.push({sz:nm.includes("12 inch")?12:8,id,pr:PR.indexOf(id)!==-1});
if(nm.includes("buffalo")&&ct==="wings")bw+=parseInt(nm)||0;
if(nm.includes("whole")&&ct==="wings")ww+=parseInt(nm)||0;
if(nm.includes("fries")||ct==="sides")fr++;
if(nm.includes("can soda"))cn++;
if(nm.includes("2 liter"))tl++;
if(nm.includes("burger sandwich")||nm.includes("cheeseburger"))bg++;
if(nm.includes("fish sandwich"))fi++;
}
const rg=su.filter(s=>!s.pr);
const no=d=>dec.indexOf(d)!==-1;
let dm=null,sg="",dn="none";
if(pz.length>=4&&bw>=48&&fr&&tl&&!no("party")){dm="party_deal";sg="Party deal";}
else if(pz.length>=3&&pz[0]===pz[1]&&pz[1]===pz[2]&&[14,16].includes(pz[0])&&tl&&!no("3pz")){dm="3_pizza";sg="3 pizza special";}
else if(pz.length>=2&&pz[0]===pz[1]&&[12,14,16,18].includes(pz[0])&&!no("dd")){dm="double_deal";sg="Double deal";}
else if(pz.length>=1&&rg.length>=1&&bw>0&&cn>=2&&!no("combo")){dm="combo_deal";sg="Combo deal";}
else if(pz.length>=1&&bw>0&&tl>0&&!no("pw")){dm="pizza_wings";sg="Pizza and wings deal";}
else if(pz.length>=1&&rg.length>=1&&fr>0&&cn>0&&!no("ps")){dm="pizza_sub";sg="Pizza sub combo";}
else if(rg.length>=1&&bw>=6&&cn>0&&!no("ws")){dm="wings_sub";sg="Wings and sub deal";}
else if(su.length>=3&&fr>=3&&cn>=3&&!no("3sc")){dm="3_sub_combo";sg="3 sub combo";}
else if(su.length>=2&&fr>=2&&cn>=2&&!no("2sc")){dm="2_sub_combo";sg="2 sub combo";}
else if(su.length>=1&&fr>0&&cn>0&&!no("sc")){dm="sub_combo";sg="Sub combo";}
else if(bw>=12&&cn>=2&&!no("cbb")){dm="chicken_box_buffalo";sg="Chicken box buffalo";}
else if(ww>=8&&cn>=2&&!no("cbw")){dm="chicken_box_whole";sg="Chicken box whole";}
else if(bw===6&&fr&&cn&&!no("wsb")){dm="wings_special_buffalo";sg="Wings special";}
else if(ww===4&&fr&&cn&&!no("wsw")){dm="wings_special_whole";sg="Whole wings special";}
else if(bg&&fr&&cn&&!no("bc")){dm="burger_combo";sg="Burger combo";}
else if(fi&&fr&&cn&&!no("fc")){dm="fish_combo";sg="Fish combo";}
if(!dm){
if(pz.length>=1&&rg.length>=1&&bw>0&&cn<2&&!no("combo")){dm="near_combo";sg="Add two cans for the combo deal?";}
else if(pz.length>=2&&pz[0]===pz[1]&&!no("dd")){dm="near_dd";sg="Double deal?";}
else if(pz.length>=1&&bw>0&&!tl&&!no("pw")){dm="near_pw";sg="Family deal with a two-liter?";}
else if(pz.length>=1&&rg.length>=1&&(!fr||!cn)&&!no("ps")){dm="near_ps";sg="Pizza sub combo with fries and soda?";}
else if(rg.length>=1&&bw>=6&&!no("ws")){dm="near_ws";sg="Wings and sub deal?";}
else if(su.length>=3&&(!fr||!cn)&&!no("3sc")){dm="near_3sc";sg="Three sub combo with fries and sodas?";}
else if(su.length>=2&&(!fr||!cn)&&!no("2sc")){dm="near_2sc";sg="Two sub combo with fries and sodas?";}
else if(su.length===1&&(!fr||!cn)&&!no("sc")){dm="near_sc";sg="Sub combo with fries and soda?";}
else if(bw===6&&(!fr||!cn)&&!no("wsb")){dm="near_wbuf";sg="Wings special with fries and soda?";}
else if(ww===4&&(!fr||!cn)&&!no("wsw")){dm="near_wwhole";sg="Whole wings special?";}
else if(bg&&(!fr||!cn)&&!no("bc")){dm="near_bc";sg="Burger combo?";}
else if(fi&&(!fr||!cn)&&!no("fc")){dm="near_fc";sg="Fish combo?";}
}
return {deal_match:dm||"none",suggestion:sg,declined_deals:JSON.stringify(dec)};

