try { items = JSON.parse(dv.basket || "[]"); } catch(e) { items = []; }
const DEALS = [769,770,771,772,773,774,775,776,777,778,780,781,782,783,784,786,787,788,793,794,831,838,839,840,744,847];
const name = dv.new_item_name;
const price = parseFloat(dv.new_item_price) || 0;
const itemId = dv.new_item_id || "";
const pid = dv.pricing_id || "none";
const lastPid = dv.last_pricing_id || "none";
const qty = parseInt(dv.new_item_quantity) || 1;
const isNew = pid !== "none" && pid !== lastPid;
let comboAdded = "no";
if (isNew && name && name !== "undefined" && name !== "none" && price > 0) {
  const isCombo = DEALS.includes(parseInt(itemId));
  if (isCombo) {
    comboAdded = "yes";
    const CC = ["pizzas","submarines","wings","sides","beverages","sandwiches"];
    items = items.filter(it => it.is_combo || CC.indexOf((it.category||"").toLowerCase()) === -1);
    items.push({ item_name: name, item_id: itemId, unit_price: price, category: "Combo", quantity: 1, is_combo: true, deal_id: itemId });
  } else {
    for (let q = 0; q < qty; q++) {
      items.push({ item_name: name, item_id: itemId, unit_price: price, category: dv.new_item_category || "", quantity: 1, is_combo: false });
    }
  }
}
let sub = 0;
for (const it of items) sub += (parseFloat(it.unit_price)||0) * (parseInt(it.quantity)||1);
sub = Math.round(sub * 100) / 100;
return { basket: JSON.stringify(items), item_count: items.length, subtotal: sub, last_pricing_id: pid, combo_added: comboAdded };

// Server already saved item to basket. Just do deal detection.
let items = [];
try { items = JSON.parse(dv.basket || "[]"); } catch(e) { items = []; }

let sub = parseFloat(dv.subtotal) || 0;
let count = parseInt(dv.item_count) || items.length;
let comboAdded = "no";

// Check if last item was a combo (from server response)
for (const it of items) {
  if (it.is_combo && it.deal_id) {
    comboAdded = "yes";
    break;
  }
}

// Auto-detect deal-worthy basket
if (comboAdded !== "yes") {
  let pz = [], su = 0, bw = 0, ww = 0, fr = 0, cn = 0, tl = 0, bg = 0, fi = 0;
  for (const it of items) {
    if (it.is_combo) continue;
    const nm = (it.item_name || "").toLowerCase();
    const ct = (it.category || "").toLowerCase();
    if (ct === "pizzas" && nm.includes("cheese pizza")) { const m = nm.match(/(\d+)\s*inch/); pz.push(m ? parseInt(m[1]) : 14); }
    if (ct === "submarines") su++;
    if (nm.includes("buffalo") && ct === "wings") bw += parseInt(nm) || 0;
    if (nm.includes("whole") && ct === "wings") ww += parseInt(nm) || 0;
    if (nm.includes("fries") || nm.includes("french")) fr++;
    if (nm.includes("can soda")) cn++;
    if (nm.includes("2 liter")) tl++;
    if (nm.includes("burger") || nm.includes("cheeseburger")) bg++;
    if (nm.includes("fish sandwich")) fi++;
  }
  if (pz.length >= 2) { const s = pz.sort(); if (s[0] === s[1]) comboAdded = "yes"; }
  if (pz.length >= 3) comboAdded = "yes";
  if (pz.length >= 1 && bw > 0) comboAdded = "yes";
  if (pz.length >= 1 && su >= 1) comboAdded = "yes";
  if (su >= 1 && bw >= 6) comboAdded = "yes";
  if (su >= 1 && fr > 0 && cn > 0) comboAdded = "yes";
  if (su >= 2 && fr >= 2 && cn >= 2) comboAdded = "yes";
  if ((bw === 6 || ww === 4) && fr > 0 && cn > 0) comboAdded = "yes";
  if ((bw >= 12 || ww >= 8) && cn >= 2) comboAdded = "yes";
  if (bg > 0 && fr > 0 && cn > 0) comboAdded = "yes";
  if (fi > 0 && fr > 0 && cn > 0) comboAdded = "yes";
}

return { basket: JSON.stringify(items), item_count: count, subtotal: sub, combo_added: comboAdded };

